@media (max-width: 480px){

    /* ── Mobile top header ── */
    .mobile-top-header{
        display: flex;
        align-items: center;
        justify-content: space-between;
        position: sticky;
        top: 0;
        z-index: 122;
        width: 100%;
        padding: 0.65rem 0.75rem;
        box-sizing: border-box;
        background: var(--bg-primary);
        border-bottom: 1px solid var(--border-card);
    }
    .mobile-brand-text{
        font-family: 'Playfair Display', serif;
        font-size: 1.4rem;
        font-weight: 700;
        color: var(--text-heading);
        letter-spacing: -0.02rem;
    }
    .mobile-header-profile-btn{
        display: flex;
        align-items: center;
        justify-content: center;
        background: none;
        border: 1.5px solid var(--border-card);
        border-radius: 50%;
        padding: 0;
        cursor: pointer;
        -webkit-tap-highlight-color: transparent;
        transition: border-color 0.2s ease;
    }
    .mobile-header-profile-btn:active{
        border-color: #D4A853;
    }
    .mobile-header-profile-btn img{
        width: 30px;
        height: 30px;
        border-radius: 50%;
        object-fit: cover;
    }

    /* ── Search bar visible on mobile ── */
    .search-shell{
        top: 0;
        position: relative;
    }
    .search-top-bar{
        padding: 0.5rem 0.5rem 0.55rem 0.5rem;
        gap: 0.4rem;
    }
    .search-input{
        font-size: 0.8rem;
        padding: 0.5rem 0.75rem 0.5rem 2.1rem;
        border-radius: 8px;
    }
    .search-icon{
        left: 0.7rem;
        width: 14px;
        height: 14px;
    }
    .search-clear-btn{
        font-size: 0.64rem;
        padding: 0.32rem 0.52rem;
        border-radius: 6px;
    }
    .search-nav-row{
        display: none;
    }
    .search-mode-pill{
        font-size: 0.58rem;
        padding: 0.28rem 0.44rem;
        border-radius: 6px;
    }

    .search-suggestions-dropdown{
        left: 0.5rem;

