                    </g>
                </svg>
            ),
        },
        {
            type: 'icon',
            label: 'Following',
            path: '/home/following',
            action: (path) => handleNavigatePath(path),
            icon: (isActive) => (
                <svg xmlns="http://www.w3.org/2000/svg" width="22px" height="22px" viewBox="0 0 24 24" fill={isActive ? activeColor : inactiveColor}>
